// AUTO-GENERATED DRAFT SCREEN: RecentActivity
import React from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import { Skeleton } from '@/components/ui/skeleton';

// Mock tRPC hook for demonstration. In a real app, this would be generated by tRPC.
interface Activity {
  id: string;
  user: { name: string; avatarUrl: string; };
  action: string;
  timestamp: string; // ISO string or similar
  type: 'login' | 'transaction' | 'update' | 'notification';
}

interface UseRecentActivityResult {
  data: Activity[] | undefined;
  isLoading: boolean;
  isError: boolean;
}

const useRecentActivity = (): UseRecentActivityResult => {
  // Simulate data fetching with a delay
  const [data, setData] = React.useState<Activity[] | undefined>(undefined);
  const [isLoading, setIsLoading] = React.useState(true);
  const [isError, setIsError] = React.useState(false);

  React.useEffect(() => {
    const fetchData = async () => {
      try {
        setIsLoading(true);
        // Simulate API call
        await new Promise(resolve => setTimeout(resolve, 1500));
        const mockActivities: Activity[] = [
          {
            id: '1',
            user: { name: 'Alice', avatarUrl: 'https://api.dicebear.com/7.x/initials/svg?seed=Alice' },
            action: 'logged in',
            timestamp: '2026-06-11T10:00:00Z',
            type: 'login',
          },
          {
            id: '2',
            user: { name: 'Bob', avatarUrl: 'https://api.dicebear.com/7.x/initials/svg?seed=Bob' },
            action: 'transferred 100 SKY',
            timestamp: '2026-06-11T09:45:00Z',
            type: 'transaction',
          },
          {
            id: '3',
            user: { name: 'Charlie', avatarUrl: 'https://api.dicebear.com/7.x/initials/svg?seed=Charlie' },
            action: 'updated profile',
            timestamp: '2026-06-11T09:30:00Z',
            type: 'update',
          },
          {
            id: '4',
            user: { name: 'David', avatarUrl: 'https://api.dicebear.com/7.x/initials/svg?seed=David' },
            action: 'received 50 SKY',
            timestamp: '2026-06-11T09:15:00Z',
            type: 'transaction',
          },
          {
            id: '5',
            user: { name: 'Eve', avatarUrl: 'https://api.dicebear.com/7.x/initials/svg?seed=Eve' },
            action: 'created a new wallet',
            timestamp: '2026-06-11T09:00:00Z',
            type: 'update',
          },
        ];
        setData(mockActivities);
      } catch (error) {
        setIsError(true);
      } finally {
        setIsLoading(false);
      }
    };
    fetchData();
  }, []);

  return { data, isLoading, isError };
};

const ActivityItem: React.FC<{ activity: Activity }> = ({ activity }) => {
  const formatTimestamp = (isoString: string) => {
    const date = new Date(isoString);
    return date.toLocaleString(); // Adjust formatting as needed
  };

  const getTypeColor = (type: Activity['type']) => {
    switch (type) {
      case 'login': return 'bg-green-500/20 text-green-600 dark:text-green-400';
      case 'transaction': return 'bg-blue-500/20 text-blue-600 dark:text-blue-400';
      case 'update': return 'bg-yellow-500/20 text-yellow-600 dark:text-yellow-400';
      case 'notification': return 'bg-purple-500/20 text-purple-600 dark:text-purple-400';
      default: return 'bg-gray-500/20 text-gray-600 dark:text-gray-400';
    }
  };

  return (
    <div className="flex items-center space-x-4 p-3 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-md transition-colors">
      <Avatar className="h-9 w-9">
        <AvatarImage src={activity.user.avatarUrl} alt={activity.user.name} />
        <AvatarFallback>{activity.user.name.charAt(0)}</AvatarFallback>
      </Avatar>
      <div className="flex-1">
        <p className="text-sm font-medium leading-none text-gray-900 dark:text-gray-100">
          {activity.user.name} <span className="font-normal text-gray-700 dark:text-gray-300">{activity.action}</span>
        </p>
        <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
          {formatTimestamp(activity.timestamp)}
        </p>
      </div>
      <Badge className={getTypeColor(activity.type)}>{activity.type}</Badge>
    </div>
  );
};

const RecentActivity: React.FC = () => {
  const { data: activities, isLoading, isError } = useRecentActivity();

  return (
    <Card className="w-full max-w-md mx-auto shadow-lg dark:bg-gray-900 dark:border-gray-700">
      <CardHeader className="border-b dark:border-gray-700">
        <CardTitle className="text-xl font-semibold text-gray-900 dark:text-gray-100">Recent Activity</CardTitle>
      </CardHeader>
      <CardContent className="p-0">
        {isLoading && (
          <div className="p-4 space-y-3">
            {[...Array(5)].map((_, i) => (
              <div key={i} className="flex items-center space-x-4">
                <Skeleton className="h-9 w-9 rounded-full" />
                <div className="space-y-2">
                  <Skeleton className="h-4 w-[200px]" />
                  <Skeleton className="h-3 w-[150px]" />
                </div>
              </div>
            ))}
          </div>
        )}

        {isError && (
          <div className="p-4 text-center text-red-600 dark:text-red-400">
            Failed to load recent activity. Please try again later.
          </div>
        )}

        {!isLoading && !isError && activities && activities.length > 0 && (
          <ScrollArea className="h-[300px]">
            <div className="p-4 space-y-3">
              {activities.map((activity) => (
                <ActivityItem key={activity.id} activity={activity} />
              ))}
            </div>
          </ScrollArea>
        )}

        {!isLoading && !isError && (!activities || activities.length === 0) && (
          <div className="p-4 text-center text-gray-500 dark:text-gray-400">
            No recent activity found.
          </div>
        )}
      </CardContent>
    </Card>
  );
};

export default RecentActivity;
